// ClaudeAnims — ClaudePix 20×20 creature animations ported to native SwiftUI.
// Source library: https://claudepix.vercel.app/  (0 empty, 1 body, 2 eye, 3+ scene)
// The cpAnimSource blob below is auto-generated; the logic here parses and
// renders it as an animated mascot (Canvas) and an animated menu-bar icon.

import SwiftUI
import AppKit

// MARK: - Model --------------------------------------------------------------

struct CPAnim {
    let palette: [Color?]      // index 0 = nil (transparent)
    let nsPalette: [CGColor?]
    let themed: Bool           // body(+eye) only → follow the app's theme colors
    let holds: [Double]        // seconds per frame
    let cells: [[UInt8]]       // frame → 400 cell indices, row-major 20×20
    let cropR: Int, cropC: Int, cropRows: Int, cropCols: Int
    let totalHold: Double       // precomputed loop duration (sum of holds)
    var frameCount: Int { holds.count }
}

private func cpHexColor(_ h: String) -> Color {
    let v = UInt64(h, radix: 16) ?? 0
    return Color(.sRGB, red: Double((v >> 16) & 0xff) / 255,
                 green: Double((v >> 8) & 0xff) / 255,
                 blue: Double(v & 0xff) / 255, opacity: 1)
}
private func cpHexCG(_ h: String) -> CGColor {
    let v = UInt64(h, radix: 16) ?? 0
    return CGColor(srgbRed: CGFloat((v >> 16) & 0xff) / 255,
                   green: CGFloat((v >> 8) & 0xff) / 255,
                   blue: CGFloat(v & 0xff) / 255, alpha: 1)
}

private func parseCPAnim(_ blob: String) -> CPAnim {
    let parts = blob.split(separator: "|", omittingEmptySubsequences: false)
    let hexes = parts.isEmpty ? [] : parts[0].split(separator: ",").map(String.init)
    var palette: [Color?] = [nil]
    var ns: [CGColor?] = [nil]
    for h in hexes { palette.append(cpHexColor(h)); ns.append(cpHexCG(h)) }
    let themed = hexes.count <= 2

    var holds: [Double] = []
    var cells: [[UInt8]] = []
    var minR = 19, minC = 19, maxR = 0, maxC = 0
    if parts.count > 1 {
        for i in 1..<parts.count {
            let fr = parts[i]
            guard let comma = fr.firstIndex(of: ",") else { continue }
            let hold = Double(fr[fr.startIndex..<comma]) ?? 120
            var arr = [UInt8](); arr.reserveCapacity(400)
            for ch in fr[fr.index(after: comma)...].utf8 where ch >= 48 && ch <= 57 {
                arr.append(ch - 48)
            }
            guard arr.count == 400 else { continue }
            for idx in 0..<400 where arr[idx] != 0 {
                let r = idx / 20, c = idx % 20
                if r < minR { minR = r }; if r > maxR { maxR = r }
                if c < minC { minC = c }; if c > maxC { maxC = c }
            }
            holds.append(hold / 1000.0)
            cells.append(arr)
        }
    }
    if maxR < minR { minR = 0; minC = 0; maxR = 19; maxC = 19 }
    return CPAnim(palette: palette, nsPalette: ns, themed: themed,
                  holds: holds, cells: cells,
                  cropR: minR, cropC: minC,
                  cropRows: maxR - minR + 1, cropCols: maxC - minC + 1,
                  totalHold: holds.reduce(0, +))
}

final class CPAnimStore {
    static let shared = CPAnimStore()
    private var cache: [String: CPAnim] = [:]
    func anim(_ name: String) -> CPAnim? {
        if let a = cache[name] { return a }
        guard let blob = cpAnimSource[name] else { return nil }
        let a = parseCPAnim(blob); cache[name] = a; return a
    }
}

private func cpFrameIndex(_ a: CPAnim, at date: Date) -> Int {
    guard a.totalHold > 0 else { return 0 }
    var t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: a.totalHold)
    for (i, h) in a.holds.enumerated() { if t < h { return i }; t -= h }
    return a.holds.count - 1
}

// MARK: - Animated mascot (SwiftUI) ------------------------------------------

struct AnimatedMascot: View {
    let name: String
    var cell: CGFloat
    var fill: Color
    var eye: Color
    var crop: Bool = true

    var body: some View {
        // Require non-empty frames: a malformed/empty anim would make
        // a.cells[min(0, -1)] trap (BarIconAnimator.attach guards the same way).
        if let a = CPAnimStore.shared.anim(name), !a.cells.isEmpty {
            let cols = crop ? a.cropCols : 20
            let rows = crop ? a.cropRows : 20
            let oC = crop ? a.cropC : 0
            let oR = crop ? a.cropR : 0
            TimelineView(.animation(minimumInterval: 0.05)) { tl in
                Canvas { ctx, _ in
                    let arr = a.cells[min(cpFrameIndex(a, at: tl.date), a.cells.count - 1)]
                    for idx in 0..<400 {
                        let v = arr[idx]
                        if v == 0 { continue }
                        let r = idx / 20, c = idx % 20
                        if crop && (r < oR || r >= oR + rows || c < oC || c >= oC + cols) { continue }
                        let color: Color = a.themed ? (v == 2 ? eye : fill)
                                                    : (a.palette[Int(v)] ?? fill)
                        let rect = CGRect(x: CGFloat(c - oC) * cell, y: CGFloat(r - oR) * cell,
                                          width: cell + 0.5, height: cell + 0.5)
                        ctx.fill(Path(rect), with: .color(color))
                    }
                }
            }
            .frame(width: cell * CGFloat(cols), height: cell * CGFloat(rows))
        } else {
            Color.clear.frame(width: cell * 20, height: cell * 20)   // matches the 20×20 grid
        }
    }
}

// MARK: - Animated menu-bar icon (AppKit) ------------------------------------

private func cpNSImage(_ a: CPAnim, _ f: Int, cell: CGFloat,
                       fill: NSColor, eye: NSColor, crop: Bool) -> NSImage {
    let oR = crop ? a.cropR : 0, oC = crop ? a.cropC : 0
    let rows = crop ? a.cropRows : 20, cols = crop ? a.cropCols : 20
    let img = NSImage(size: NSSize(width: CGFloat(cols) * cell, height: CGFloat(rows) * cell))
    img.lockFocus()
    if let ctx = NSGraphicsContext.current?.cgContext {
        let arr = a.cells[min(f, a.cells.count - 1)]
        for idx in 0..<400 {
            let v = arr[idx]
            if v == 0 { continue }
            let r = idx / 20, c = idx % 20
            if r < oR || r >= oR + rows || c < oC || c >= oC + cols { continue }
            let cg: CGColor = a.themed ? (v == 2 ? eye.cgColor : fill.cgColor)
                                       : (a.nsPalette[Int(v)] ?? fill.cgColor)
            ctx.setFillColor(cg)
            // NSImage is bottom-up; flip the row index.
            ctx.fill(CGRect(x: CGFloat(c - oC) * cell,
                            y: CGFloat((rows - 1) - (r - oR)) * cell,
                            width: cell + 0.3, height: cell + 0.3))
        }
    }
    img.unlockFocus()
    img.isTemplate = false
    return img
}

final class BarIconAnimator {
    private weak var button: NSStatusBarButton?
    private var imgs: [NSImage] = []
    private var holds: [Double] = []
    private var i = 0
    private var timer: Timer?

    // Build the frames and show the first one, but DON'T start animating — the
    // icon only animates while the popover is open (see start()/stop()), so a
    // closed, unseen menu bar costs nothing and App Nap can kick in.
    func attach(to button: NSStatusBarButton, name: String, cell: CGFloat,
                fill: NSColor, eye: NSColor, crop: Bool = true) {
        self.button = button
        guard let a = CPAnimStore.shared.anim(name), a.frameCount > 0 else { return }
        imgs = (0..<a.frameCount).map { cpNSImage(a, $0, cell: cell, fill: fill, eye: eye, crop: crop) }
        holds = a.holds
        i = 0
        button.image = imgs.first
        button.imagePosition = .imageLeading
    }

    func start() {
        guard !imgs.isEmpty else { return }
        i = 0
        button?.image = imgs.first
        step()
    }

    private func step() {
        timer?.invalidate()
        guard imgs.count > 1 else { return }
        let h = max(0.04, holds[i])
        let t = Timer(timeInterval: h, repeats: false) { [weak self] _ in
            guard let self = self else { return }
            self.i = (self.i + 1) % self.imgs.count
            self.button?.image = self.imgs[self.i]
            self.step()
        }
        timer = t
        RunLoop.main.add(t, forMode: .common)   // keeps animating while menu is tracking
    }

    func stop() {
        timer?.invalidate(); timer = nil
        if !imgs.isEmpty { i = 0; button?.image = imgs.first }   // rest on frame 0
    }
}
